#!/usr/bin/env python3
"""Tests for the binary codec round-trip.

Tests encode -> decode round-trip for various data types and edge cases.
All tests are deterministic.
"""

import sys
import os

sys.path.insert(0, os.getcwd())
from codec import encode, decode, encode_optional, encode_varint, decode_varint, decode_value, TAG_OPTIONAL

failures = []


def test_roundtrip_null():
    """None encodes and decodes correctly."""
    data = None
    encoded = encode(data)
    decoded = decode(encoded)
    if decoded is not None:
        failures.append(f"FAIL test_roundtrip_null: expected None, got {decoded!r}")
    else:
        print("PASS test_roundtrip_null")


def test_roundtrip_bool():
    """Booleans encode and decode correctly."""
    for val in [True, False]:
        encoded = encode(val)
        decoded = decode(encoded)
        if decoded != val or not isinstance(decoded, bool):
            failures.append(f"FAIL test_roundtrip_bool: {val} -> {decoded!r}")
            return
    print("PASS test_roundtrip_bool")


def test_roundtrip_integers():
    """Integers including zero and large values."""
    test_values = [0, 1, 127, 128, 255, 256, 300, 10000, 1000000]
    for val in test_values:
        encoded = encode(val)
        decoded = decode(encoded)
        if decoded != val:
            failures.append(
                f"FAIL test_roundtrip_integers: {val} -> {decoded!r}"
            )
            return
    print("PASS test_roundtrip_integers")


def test_roundtrip_negative_int():
    """Negative integers use zigzag encoding."""
    test_values = [-1, -128, -10000]
    for val in test_values:
        encoded = encode(val)
        decoded = decode(encoded)
        if decoded != val:
            failures.append(
                f"FAIL test_roundtrip_negative_int: {val} -> {decoded!r}"
            )
            return
    print("PASS test_roundtrip_negative_int")


def test_roundtrip_strings():
    """Strings including empty string and unicode."""
    test_values = ["", "hello", "world", "hello world", "unicode: \u00e9\u00e0\u00fc\u00f1"]
    for val in test_values:
        encoded = encode(val)
        decoded = decode(encoded)
        if decoded != val:
            failures.append(
                f"FAIL test_roundtrip_strings: {val!r} -> {decoded!r}"
            )
            return
    print("PASS test_roundtrip_strings")


def test_roundtrip_bytes():
    """Bytes including empty bytes."""
    test_values = [b"", b"\x00", b"\xff\x00\x01", b"hello"]
    for val in test_values:
        encoded = encode(val)
        decoded = decode(encoded)
        if decoded != val:
            failures.append(
                f"FAIL test_roundtrip_bytes: {val!r} -> {decoded!r}"
            )
            return
    print("PASS test_roundtrip_bytes")


def test_roundtrip_list():
    """Lists including empty list and mixed types."""
    test_values = [
        [],
        [1, 2, 3],
        ["a", "b", "c"],
        [1, "two", None, True, False],
    ]
    for val in test_values:
        encoded = encode(val)
        decoded = decode(encoded)
        if decoded != val:
            failures.append(
                f"FAIL test_roundtrip_list: {val!r} -> {decoded!r}"
            )
            return
    print("PASS test_roundtrip_list")


def test_roundtrip_record():
    """Records (dicts) including empty and nested."""
    test_values = [
        {},
        {"name": "alice", "age": 30},
        {"a": 1, "b": "two", "c": None},
    ]
    for val in test_values:
        encoded = encode(val)
        decoded = decode(encoded)
        if decoded != val:
            failures.append(
                f"FAIL test_roundtrip_record: {val!r} -> {decoded!r}"
            )
            return
    print("PASS test_roundtrip_record")


def test_roundtrip_nested():
    """Deeply nested structures."""
    val = {
        "users": [
            {"name": "alice", "scores": [100, 95, 87]},
            {"name": "bob", "scores": [72, 88]},
        ],
        "metadata": {
            "version": 2,
            "tags": ["test", "benchmark"],
        },
    }
    encoded = encode(val)
    decoded = decode(encoded)
    if decoded != val:
        failures.append(
            f"FAIL test_roundtrip_nested: decoded doesn't match original"
        )
    else:
        print("PASS test_roundtrip_nested")


def test_roundtrip_optional():
    """Optional values with presence byte."""
    # Test absent optional
    encoded_absent = encode_optional(None)
    assert encoded_absent[0] == TAG_OPTIONAL
    assert encoded_absent[1] == 0x00
    val_absent, offset_absent = decode_value(encoded_absent, 0)
    if val_absent is not None:
        failures.append(
            f"FAIL test_roundtrip_optional: absent optional decoded as {val_absent!r}"
        )
        return

    # Test present optional with a string
    encoded_present = encode_optional("hello")
    assert encoded_present[0] == TAG_OPTIONAL
    assert encoded_present[1] == 0x01
    val_present, offset_present = decode_value(encoded_present, 0)
    if val_present != "hello":
        failures.append(
            f"FAIL test_roundtrip_optional: present optional decoded as {val_present!r}"
        )
        return

    # Test present optional with zero
    encoded_zero = encode_optional(0)
    val_zero, _ = decode_value(encoded_zero, 0)
    if val_zero != 0:
        failures.append(
            f"FAIL test_roundtrip_optional: optional(0) decoded as {val_zero!r}"
        )
        return

    print("PASS test_roundtrip_optional")


def test_varint_roundtrip():
    """Varint encoding round-trips correctly."""
    test_values = [0, 1, 127, 128, 255, 256, 300, 16383, 16384, 1000000]
    for val in test_values:
        encoded = encode_varint(val)
        decoded, offset = decode_varint(encoded, 0)
        if decoded != val:
            failures.append(
                f"FAIL test_varint_roundtrip: {val} -> encoded {encoded.hex()} -> {decoded}"
            )
            return
        if offset != len(encoded):
            failures.append(
                f"FAIL test_varint_roundtrip: {val} offset {offset} != len {len(encoded)}"
            )
            return
    print("PASS test_varint_roundtrip")


def test_edge_case_empty_nested():
    """Edge case: record with empty list and empty string values."""
    val = {"items": [], "name": "", "data": b"", "nothing": None}
    encoded = encode(val)
    decoded = decode(encoded)
    if decoded != val:
        failures.append(
            f"FAIL test_edge_case_empty_nested: {val!r} -> {decoded!r}"
        )
    else:
        print("PASS test_edge_case_empty_nested")


def test_list_of_records():
    """List containing multiple records."""
    val = [
        {"id": 1, "label": "first"},
        {"id": 2, "label": "second"},
        {"id": 3, "label": "third"},
    ]
    encoded = encode(val)
    decoded = decode(encoded)
    if decoded != val:
        failures.append(
            f"FAIL test_list_of_records: decoded doesn't match original"
        )
    else:
        print("PASS test_list_of_records")


if __name__ == "__main__":
    test_varint_roundtrip()
    test_roundtrip_null()
    test_roundtrip_bool()
    test_roundtrip_integers()
    test_roundtrip_negative_int()
    test_roundtrip_strings()
    test_roundtrip_bytes()
    test_roundtrip_list()
    test_roundtrip_record()
    test_roundtrip_nested()
    test_roundtrip_optional()
    test_edge_case_empty_nested()
    test_list_of_records()

    if failures:
        print(f"\n{'=' * 60}")
        print(f"FAILURES ({len(failures)}):")
        for f in failures:
            print(f"  {f}")
        sys.exit(1)
    else:
        print(f"\n{'=' * 60}")
        print("ALL TESTS PASSED")
        sys.exit(0)
